// MARK: - BrandTextStyle

/// Semantic text style pairings combining a font and its standard foreground color.
public enum BrandTextStyle {
    case display
    case title
    case subtitle
    case sectionTitle
    case headline
    case body
    case callout
    case subheadline
    case caption
    case label
    case button
    case navTitle
    case onPrimary
}

// MARK: - BrandTextStyleModifier

private struct BrandTextStyleModifier: ViewModifier {
    let style: BrandTextStyle

    func body(content: Content) -> some View {
        switch style {
        case .display:
            content
                .font(BrandTypography.display)
                .foregroundStyle(BrandColors.onBackground)
        case .title:
            content
                .font(BrandTypography.title)
                .foregroundStyle(BrandColors.onBackground)
        case .subtitle:
            content
                .font(BrandTypography.subtitle)
                .foregroundStyle(BrandColors.onBackground)
        case .sectionTitle:
            content
                .font(BrandTypography.sectionTitle)
                .foregroundStyle(BrandColors.onBackground)
        case .headline:
            content
                .font(BrandTypography.headline)
                .foregroundStyle(BrandColors.onBackground)
        case .body:
            content
                .font(BrandTypography.body)
                .foregroundStyle(BrandColors.onBackground)
        case .callout:
            content
                .font(BrandTypography.callout)
                .foregroundStyle(BrandColors.onBackgroundSecondary)
        case .subheadline:
            content
                .font(BrandTypography.subheadline)
                .foregroundStyle(BrandColors.onBackgroundSecondary)
        case .caption:
            content
                .font(BrandTypography.caption)
                .foregroundStyle(BrandColors.onBackgroundSecondary)
        case .label:
            content
                .font(BrandTypography.label)
                .foregroundStyle(BrandColors.onBackgroundSecondary)
        case .button:
            content
                .font(BrandTypography.button)
                .foregroundStyle(BrandColors.onBackground)
        case .navTitle:
            content
                .font(BrandTypography.navTitle)
                .foregroundStyle(BrandColors.onBackground)
        case .onPrimary:
            content
                .font(BrandTypography.body)
                .foregroundStyle(BrandColors.onPrimary)
        }
    }
}

// MARK: - View Extension

public extension View {
    /// Applies a semantic brand text style (font + foreground color pairing).
    ///
    /// Example:
    /// ```swift
    /// Text("Hello").brandStyle(.headline)
    /// ```
    func brandStyle(_ style: BrandTextStyle) -> some View {
        self.modifier(BrandTextStyleModifier(style: style))
    }
}
